const html = $json["html"] || "";

// Etapa 1: extrair o RAW_TEXT de dentro do HTML
const rawTextMatch = html.match(/const RAW_TEXT = `([\s\S]*?)`;/);
if (!rawTextMatch) {
  throw new Error("RAW_TEXT não encontrado no HTML.");
}

const rawText = rawTextMatch[1];

// Etapa 2: transforma o rawText em linhas e colunas
const lines = rawText
  .split(/\r?\n/)
  .map(line => line.trim())
  .filter(Boolean);

if (lines.length < 2) {
  throw new Error("Texto não contém dados suficientes.");
}

const headers = lines[0].split('|').map(h => h.trim());
const dataRows = lines.slice(1).map(line => {
  const values = line.split('|').map(v => v.trim());
  const obj = {};
  headers.forEach((key, i) => {
    obj[key] = values[i] || "";
  });
  return obj;
});

// Etapa 3: gerar tabela em Markdown
let markdown = `| ${headers.join(' | ')} |\n`;
markdown += `| ${headers.map(() => '---').join(' | ')} |\n`;

dataRows.forEach(row => {
  const rowLine = headers.map(h => row[h]).join(' | ');
  markdown += `| ${rowLine} |\n`;
});

return [
  {
    json: {
      message: markdown
    }
  }
];
